import{_ as o,c as i,o as c,ah as a}from"./chunks/framework.DtKbHGNi.js";const p=JSON.parse('{"title":"基本命令：设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/Kits/git_learn.md","filePath":"docs/Kits/git_learn.md","lastUpdated":1782446547000}'),d={name:"docs/Kits/git_learn.md"};function l(t,e,r,h,n,s){return c(),i("div",null,e[0]||(e[0]=[a('<h1 id="基本命令-设置" tabindex="-1">基本命令：设置 <a class="header-anchor" href="#基本命令-设置" aria-label="Permalink to “基本命令：设置”">​</a></h1><h2 id="初始化git仓库-init" tabindex="-1">初始化git仓库 <code>init</code> <a class="header-anchor" href="#初始化git仓库-init" aria-label="Permalink to “初始化git仓库 init”">​</a></h2><p><code>git init</code></p><h2 id="设置用户名和邮箱-config" tabindex="-1">设置用户名和邮箱 <code>config</code> <a class="header-anchor" href="#设置用户名和邮箱-config" aria-label="Permalink to “设置用户名和邮箱 config”">​</a></h2><ul><li>用户名：<code>git config user.name xxx</code> 设置了用户名为xxx；<code>git config user.name &quot;xxx xx&quot;</code> 设置包含空格的用户名</li><li>邮箱：<code>git config user.email xxx</code> 设置了邮箱为xxx</li><li>查看：<code>git config user.name</code> <code>git config user.email</code></li></ul><p>其他设置：</p><ul><li><code>merge.ff no</code>: 设置为分支合并不用快进式合并</li><li><code>push.default matching [or] simple</code>: <code>git push</code> 采用matching模式（推送所有有对应的远程分支的本地分支）还是simple模式（只推送当前分支）</li></ul><h3 id="core" tabindex="-1">core <a class="header-anchor" href="#core" aria-label="Permalink to “core”">​</a></h3><ul><li><code>core.fileMode</code> 是否保存文件权限，设置为false后，文件权限的改变不会触发状态的修改</li></ul><h3 id="option" tabindex="-1">option <a class="header-anchor" href="#option" aria-label="Permalink to “option”">​</a></h3><p><code>--global</code> 作为全局设置。优先局部的值；存放在 <code>.gitconfig</code> 文件中</p><p>信息存放在 <code>./.git/config</code> 中</p><h1 id="基本命令-查看" tabindex="-1">基本命令：查看 <a class="header-anchor" href="#基本命令-查看" aria-label="Permalink to “基本命令：查看”">​</a></h1><h2 id="查看状态-status" tabindex="-1">查看状态 <code>status</code> <a class="header-anchor" href="#查看状态-status" aria-label="Permalink to “查看状态 status”">​</a></h2><p><code>git status</code> 查看当前仓库的状态，包括分支、修改和提交信息</p><h2 id="查看提交信息-log" tabindex="-1">查看提交信息 <code>log</code> <a class="header-anchor" href="#查看提交信息-log" aria-label="Permalink to “查看提交信息 log”">​</a></h2><p><code>git log</code>: 打印最近的提交，根据屏幕大小决定输出多少。按 <code>Enter</code> 键继续输出一行，按 <code>Q</code> 键退出</p><h3 id="option-1" tabindex="-1">option <a class="header-anchor" href="#option-1" aria-label="Permalink to “option”">​</a></h3><p><code>--oneline</code> 每个提交只输出一行</p><h2 id="标签-tag" tabindex="-1">标签 <code>tag</code> <a class="header-anchor" href="#标签-tag" aria-label="Permalink to “标签 tag”">​</a></h2><p><code>git tag</code>: 查看所有的标签信息</p><h3 id="option-2" tabindex="-1">option <a class="header-anchor" href="#option-2" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-a</code> 添加标签，如：<code>git tag -a tag0 -m &quot;this is a commit tagged tag0&quot;</code> 在当前提交中添加了一个tag0并指定一条存储在该标签中的信息</li><li><code>-d</code> 删除指定标签，如：<code>git tag -d tag0</code></li></ul><h2 id="比较-diff-与-difftool" tabindex="-1">比较 <code>diff</code> 与 <code>difftool</code> <a class="header-anchor" href="#比较-diff-与-difftool" aria-label="Permalink to “比较 diff 与 difftool”">​</a></h2><p>比较文件的不同，有多种用法：</p><ul><li>工作区和暂存区（<code>git add .</code> 后的） <ul><li><code>git diff</code> 比较工作区和暂存区的不同；<code>git diff -- {文件名1} {文件名2}</code> 比较工作区和暂存区中指定文件之间的不同</li></ul></li><li>工作区和版本库 <ul><li><code>git diff HEAD</code> 比较工作区和最新版本库中的不同；<code>git diff HEAD -- {文件名1} {文件名2}</code> 比较工作区和最新版本库中指定文件之间的不同</li><li><code>git diff {hash number}</code> 比较工作区和最新版本库中的不同；<code>git diff {hash number} -- {文件名1} {文件名2}</code> 比较工作区和最新版本库中指定文件之间的不同</li></ul></li><li>暂存区和版本库 <ul><li><code>git diff --cached</code> 比较暂存区和最新版本库中的不同；<code>git diff --cached -- {文件名1} {文件名2}</code> 比较暂存区和最新版本库中指定文件之间的不同</li><li><code>git diff --cached {hash number}</code> 比较暂存区和版本库中的不同；<code>git diff --cached {hash number} -- {文件名1} {文件名2}</code> 比较暂存区和版本库中指定文件之间的不同</li></ul></li><li>不同版本之间 <ul><li><code>git diff {hash number1} {hash number2}</code> 比较两个版本的不同；<code>git diff {hash number1} {hash number2} -- {文件名1} {文件名2}</code> 比较两个版本指定文件之间的不同；<code>git diff {hash number1} {hash number2} src</code> 比较两个版本在 <code>src</code> 文件夹的不同</li><li><code>git diff {hash number1} {hash number2} --stat</code> 查看版本间改动的文件列表</li></ul></li></ul><p><code>git difftool</code> 是差不多的，就是用一个图形界面（vim类型的）进行比较</p><h1 id="基本命令-提交" tabindex="-1">基本命令：提交 <a class="header-anchor" href="#基本命令-提交" aria-label="Permalink to “基本命令：提交”">​</a></h1><h2 id="添加-add" tabindex="-1">添加 <code>add</code> <a class="header-anchor" href="#添加-add" aria-label="Permalink to “添加 add”">​</a></h2><ul><li><code>git add xxx.cpp</code> 添加了 <code>xxx.cpp</code> 到 <code>HEAD</code> 分支（指向当前工作区状态的分支/指针），待提交</li><li><code>git add .</code> 添加了当前仓库中所有已更改的文件到缓存区</li></ul><h2 id="提交-commit" tabindex="-1">提交 <code>commit</code> <a class="header-anchor" href="#提交-commit" aria-label="Permalink to “提交 commit”">​</a></h2><ul><li><code>git commit -m &quot;提交信息&quot;</code> 提交缓存区的部分</li><li><code>git commit</code> 在终端运行也可以，进入 <code>vim</code> 界面进行编辑，且可以编辑多行提交信息</li></ul><h3 id="提交规范" tabindex="-1">提交规范 <a class="header-anchor" href="#提交规范" aria-label="Permalink to “提交规范”">​</a></h3><blockquote><p><a href="https://zhuanlan.zhihu.com/p/182553920" target="_blank" rel="noreferrer">如何规范你的Git commit？</a> by 阿里云开发者，知乎</p></blockquote><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&gt;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">scope</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">subject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><strong>type</strong> (必须):</p><ul><li><code>feat</code>：新功能（feature）</li><li><code>fix/to</code>：修复bug，可以是QA发现的BUG，也可以是研发自己发现的BUG。 <ul><li><code>fix</code>：产生diff并自动修复此问题。适合于一次提交直接修复问题</li><li><code>to</code>：只产生diff不自动修复此问题。适合于多次提交。最终修复问题提交时使用fix</li></ul></li><li><code>docs</code>：文档（documentation）。</li><li><code>style</code>：格式（不影响代码运行的变动）：代码的格式和风格，使其符合项目的编码规范</li><li><code>refactor</code>：重构（即不是新增功能，也不是修改bug的代码变动）：对代码的逻辑、架构或设计进行修改，目的是提高代码的可读性、可维护性和可扩展性，但最终结果（从外部看）和修改前一模一样</li><li><code>perf</code>：优化相关，比如提升性能、体验。</li><li><code>test</code>：增加测试。</li><li><code>chore</code>：构建过程或辅助工具的变动。</li><li><code>revert</code>：回滚到上一个版本。</li><li><code>merge</code>：代码合并。</li><li><code>sync</code>：同步主线或分支的Bug。</li></ul><p><strong>scope</strong>(可选)：scope用于说明 commit 影响的范围，比如数据层、控制层、视图层等等，视项目不同而不同。</p><p><strong>subject</strong>(必须)：subject是commit目的的简短描述，不超过50个字符。</p><h2 id="撤销-reset" tabindex="-1">撤销 <code>reset</code> <a class="header-anchor" href="#撤销-reset" aria-label="Permalink to “撤销 reset”">​</a></h2><ul><li><code>git reset xxx.cpp</code> 撤销了 <code>xxx.cpp</code> 的添加</li><li><code>git reset</code> 撤销了所有添加的内容</li><li><code>git reset {hash ID}</code> （软撤回）撤回到该提交中，之后的提交都被删除。但只是撤回了提交，原文件的内容仍然保存</li><li><code>git reset --hard {hash ID}</code> （硬撤回）撤回到该提交中，之后的提交都被删除，原文件也被相应修改</li></ul><h1 id="基本命令-分支" tabindex="-1">基本命令：分支 <a class="header-anchor" href="#基本命令-分支" aria-label="Permalink to “基本命令：分支”">​</a></h1><h2 id="分支-branch" tabindex="-1">分支 <code>branch</code> <a class="header-anchor" href="#分支-branch" aria-label="Permalink to “分支 branch”">​</a></h2><p><code>git branch</code> 查看所有分支，默认的分支为 <code>main</code>；加 <code>*</code> 的为当前分支</p><h3 id="option-3" tabindex="-1">option <a class="header-anchor" href="#option-3" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-a</code>: 查看所有分支：<code>git branch -a</code></li><li><code>-d</code>：删除分支，如：<code>git branch -d beta</code> 删除 <code>beta</code> 分支。注意，当前分支无法被删除，需要先切换到其他分支再执行删除命令</li><li><code>-m</code>: 重命名或移动分支，如：<code>git branch -m beta1</code> 重命名<strong>当前分支</strong>为 <code>beta1</code> 分支</li><li><code>-r</code>: 查看远程分支：<code>git branch -r</code></li><li><code>-v</code>: 显示每个分支的最后一次提交信息。</li><li><code>--set-upstream</code> 手动建立追踪关系 <code>git branch --set-upstream-to=origin/next master</code></li></ul><h2 id="切换-checkout" tabindex="-1">切换 <code>checkout</code> <a class="header-anchor" href="#切换-checkout" aria-label="Permalink to “切换 checkout”">​</a></h2><p><code>git checkout {hash ID}</code> 回溯到之前提交的状态。其中 <code>{hash ID}</code> 在 <code>git log</code> 中可以查看。</p><p>除了 <code>{hash ID}</code>，也可以：</p><ul><li>使用 <code>git checkout main</code> 回到 <code>main</code> 分支</li><li>使用 <code>git checkout tag0</code> 回到 <code>tag0</code> 标签的提交</li></ul><h3 id="option-4" tabindex="-1">option <a class="header-anchor" href="#option-4" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-b</code>: 创建并切换为该分支，如 <code>git checkout -b beta</code> 创建并切换到 <code>beta</code> 分支上。若分支名称存在会报错； <ul><li><code>git checkout -b beta origin/master</code> 表示在分支 <code>origin/master</code> 的基础上创建新分支</li><li>分支命名规范：不能包含空格；可以加 <code>/</code>；可以包含中文和特殊字符</li><li>命名：<code>beta</code> 代表创新，尝试一些新东西</li><li>命名：可以使用开发者/做什么事来命名</li></ul></li><li><code>-B</code>:</li></ul><h2 id="合并-merge" tabindex="-1">合并 <code>merge</code> <a class="header-anchor" href="#合并-merge" aria-label="Permalink to “合并 merge”">​</a></h2><p><code>git merge {branch}</code>: 将分支合并到当前分支上，如：<code>git merge beta</code> 将 <code>beta</code> 分支的提交合并到当前分支上。</p><ul><li>当当前分支没有新的提交时，使用 <code>git merge {branch}</code> 产生快进式合并(fast forward, ff)，此时看不出分支的结构，合并后是一条直线</li><li>当当前分支有新的提交时，使用 <code>git merge {branch}</code> 会产生一个合并提交，此时可以看到分支的结构。注意：可能会有冲突</li></ul><p>处理冲突： 2个分支的修改可能出现冲突，比如共同修改了同一个文件的同一行，使用合并命令后出现冲突。此时在原文件中出现： <code>&lt;&lt;&lt;&lt;HEAD</code> <code>&gt;&gt;&gt;&gt;beta</code> 让你选择当前分支的还是被合并分支的修改，还是都接收，一个在上一行，一个在下一行</p><h3 id="option-5" tabindex="-1">option <a class="header-anchor" href="#option-5" aria-label="Permalink to “option”">​</a></h3><ul><li><code>--no-ff</code>: 不使用快进式合并，创建一个新的节点进行合并，合并后进入 vim 界面编辑合并信息</li><li><code>--squash</code>: 将分支的所有提交合并成一个提交，合并后进入 vim 界面编辑提交信息，合并后不会有分支结构</li><li><code>--allow-unrelated-histories</code>: 允许合并没有共同祖先的分支</li></ul><h2 id="重构-rebase" tabindex="-1">重构 <code>rebase</code> <a class="header-anchor" href="#重构-rebase" aria-label="Permalink to “重构 rebase”">​</a></h2><p><code>git rebase origin/master</code> 合并分支到当前分支，与 <code>git merge</code> 的区别在于合并后不会出现合并前的分支，而是将原来分支在当前分支中重构，相当于在当前分支进行提交。</p><h3 id="option-6" tabindex="-1">option <a class="header-anchor" href="#option-6" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-i</code>: <code>git rebase -i {hash ID}</code>: 进入交互式界面<strong>修改提交信息</strong>，终端编辑 <ul><li><code>r, reword</code> 重新编辑该提交，然后进入第二个vim编辑界面进行重新编辑</li><li><code>s, squash</code> 合并之前的提交，然后进入第二个vim编辑界面编辑提交信息，但是看不出合并过</li></ul></li><li><code>--onto</code>: <code>git rebase --onto {hash ID1} {hash ID2}</code>: 合并特定的提交</li></ul><h2 id="cherry-pick" tabindex="-1"><code>cherry-pick</code> <a class="header-anchor" href="#cherry-pick" aria-label="Permalink to “cherry-pick”">​</a></h2><p><code>git cherry-pick &lt;commit-hash&gt;</code> 合并分支到当前分支，与前者的区别在于只将一个<strong>特定的提交</strong>“复制”并合并在当前分支上</p><p>多个commit的合并：</p><ul><li><code>git cherry-pick &lt;commit-hash1&gt; &lt;commit-hash2&gt;</code>: 提交2个commit的合并</li><li><code>git cherry-pick &lt;commit-hash1&gt;..&lt;commit-hash2&gt;</code>: 提交从 <code>commit-hash1</code> 到 <code>commit-hash2</code> 的合并，且不包含 <code>commit-hash1</code></li><li><code>git cherry-pick &lt;commit-hash1&gt;^..&lt;commit-hash2&gt;</code>: 挑选从 <code>commit-hash1</code> 的父提交之后，到 <code>commit-hash2</code> 之间的所有提交，包含 <code>commit-hash1</code> 和 <code>commit-hash2</code>。</li></ul><p>若出现冲突，需要先解决冲突后再提交，解决冲突后使用 <code>git add .</code> 将修改添加到暂存区，然后使用 <code>git cherry-pick --continue</code> 继续合并</p><h3 id="option-7" tabindex="-1">option <a class="header-anchor" href="#option-7" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-e</code> / <code>--edit</code>: 在提交前编辑提交信息</li><li><code>--no-commit</code> 直接合并，不提交</li><li><code>-s</code> / <code>--signoff</code> 在提交信息最后添加 <code>Signed-off-by</code> 线</li><li><code>-x</code>: 添加一条线表明从哪来</li><li><code>--abort</code>: 中断之前的 <code>cherry-pick</code></li><li><code>--continue</code>: 解决掉版本冲突后继续 <code>cherry-pick</code></li></ul><h1 id="基本命令-远程仓库" tabindex="-1">基本命令：远程仓库 <a class="header-anchor" href="#基本命令-远程仓库" aria-label="Permalink to “基本命令：远程仓库”">​</a></h1><h2 id="克隆-clone" tabindex="-1">克隆 <code>clone</code> <a class="header-anchor" href="#克隆-clone" aria-label="Permalink to “克隆 clone”">​</a></h2><p><code>git clone &lt;版本库的网址&gt;</code> 克隆远程仓库到本地；<code>git clone &lt;版本库的网址&gt; &lt;本地目录名&gt;</code></p><p>支持多种协议，除了 <code>http[s]</code> ，还支持 <code>ssh</code> <code>git</code> 本地文件协议</p><ul><li>克隆github的仓库，比如：<code>git clone https://github.com/xxx/xx.git</code></li><li><code>ssh</code> 协议：<code>git clone ssh://example.com/path/to/repo.git/</code> 或者 <code>git clone [user@]example.com:path/to/repo.git/</code></li><li><code>git clone git://example.com/path/to/repo.git/</code></li><li><code>git clone file:///opt/git/project.git</code></li><li><ul><li>克隆本地中的其他仓库：<code>git clone xx</code> xx是仓库名称</li></ul></li></ul><p>原始的仓库称为 <code>origin</code></p><p>在 <code>git clone</code> 的时候，所有本地分支默认与<strong>远程主机的同名分支</strong>建立追踪关系(tracking)</p><h3 id="option-8" tabindex="-1">option <a class="header-anchor" href="#option-8" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-o</code> 指定远程主机名称</li><li><code>--depth</code> 指定克隆深度</li><li><code>--branch</code> 指定克隆的分支</li></ul><h2 id="管理主机名-remote" tabindex="-1">管理主机名 <code>remote</code> <a class="header-anchor" href="#管理主机名-remote" aria-label="Permalink to “管理主机名 remote”">​</a></h2><p><code>git remote</code> 查看到原始仓库；</p><h3 id="其他操作" tabindex="-1">其他操作 <a class="header-anchor" href="#其他操作" aria-label="Permalink to “其他操作”">​</a></h3><ul><li><code>git remote get-url origin</code> 查看原始仓库的路径</li><li><code>git remote set-url origin https://github.com/dc-cl/a</code> 修改/设置原始仓库的路径</li><li><code>git remote show origin</code> 查看原始仓库的详细信息</li><li><code>git remote add &lt;主机名&gt;</code> 添加远程主机</li><li><code>git remote rm origin</code> 删除远程主机</li><li><code>git remote remove origin</code> 移除远程主机</li><li><code>git remote rename origin origin0</code> 重命名</li></ul><h3 id="option-9" tabindex="-1">option <a class="header-anchor" href="#option-9" aria-label="Permalink to “option”">​</a></h3><p><code>-v</code> 查看远程主机的网址，如 <code>git remote -v</code></p><h2 id="同步到本地-fetch" tabindex="-1">同步到本地 <code>fetch</code> <a class="header-anchor" href="#同步到本地-fetch" aria-label="Permalink to “同步到本地 fetch”">​</a></h2><p><code>git fetch &lt;远程主机名&gt;</code> 将远程主机的版本库更新取回本地，通常查看其他人的进程</p><p><code>git fetch &lt;远程主机名&gt; &lt;分支名&gt;</code> 只拉取特定分支的更新，如 <code>git fetch origin master</code></p><p>取回的更新用 <code>远程主机名/分支名</code> 的形式读取，如： <code>[remotes/]origin/master</code></p><h2 id="同步到本地且合并-pull" tabindex="-1">同步到本地且合并 <code>pull</code> <a class="header-anchor" href="#同步到本地且合并-pull" aria-label="Permalink to “同步到本地且合并 pull”">​</a></h2><p><code>git pull &lt;远程主机名&gt; &lt;远程分支名&gt;:&lt;本地分支名&gt;</code> 取回远程主机某个分支的更新，再与本地的指定分支合并</p><p><code>git pull &lt;远程主机名&gt; &lt;远程分支名&gt;</code> 取回远程主机某个分支的更新，再与本地的<strong>当前</strong>分支合并</p><p><code>git pull</code> 等同于 <code>git fetch &lt;远程主机名&gt;</code> + <code>git merge &lt;远程主机名&gt;/&lt;远程分支名&gt;</code></p><p>若当前分支与远程分支存在追踪关系，<code>git pull</code> 就可以省略远程分支名：<code>git pull origin</code></p><p>如果当前分支只有一个追踪分支，连远程主机名都可以省略：<code>git pull</code></p><h3 id="option-10" tabindex="-1">option <a class="header-anchor" href="#option-10" aria-label="Permalink to “option”">​</a></h3><ul><li><code>--rebase</code> 合并采用rebase模式</li><li><code>-p</code> 当远程主机删除了某个分支，拉取远程分支的时候，删除对应的本地分支</li></ul><h2 id="推送到远程-push" tabindex="-1">推送到远程 <code>push</code> <a class="header-anchor" href="#推送到远程-push" aria-label="Permalink to “推送到远程 push”">​</a></h2><p>将本地分支的更新，推送到远程主机，格式与 <code>git pull</code> 命令相仿（先本地分支，再远程分支）：<code>git push &lt;远程主机名&gt; &lt;本地分支名&gt;:&lt;远程分支名&gt;</code></p><p>如果省略<strong>远程分支名</strong>，则表示将本地分支推送与之存在&quot;追踪关系&quot;的远程分支（通常两者同名），如果该远程分支不存在，则会被新建。</p><p>如果省略<strong>本地分支名</strong>，则表示删除指定的远程分支，因为这等同于推送一个空的本地分支到远程分支。</p><p>如果当前分支与远程分支之间存在追踪关系，则本地分支和远程分支都可以省略：<code>git push origin</code></p><p>如果当前分支只有一个追踪分支，连远程主机名都可以省略：<code>git push</code></p><h3 id="option-11" tabindex="-1">option <a class="header-anchor" href="#option-11" aria-label="Permalink to “option”">​</a></h3><ul><li><code>-u</code> 指定一个默认主机（若当前分支与多个主机存在追踪关系），后面可以不加任何参数使用</li><li><code>all</code> 不管是否存在对应的远程分支，将本地的所有分支都推送到远程主机 <code>git push --all origin</code></li><li><code>--force</code> 强制推送，用于远程主机的版本比本地版本更新。</li><li><code>tags</code> 推送标签</li></ul><h2 id="部分拉取-显示-sparse-checkout" tabindex="-1">部分拉取 / 显示 <code>sparse-checkout</code> <a class="header-anchor" href="#部分拉取-显示-sparse-checkout" aria-label="Permalink to “部分拉取 / 显示 sparse-checkout”">​</a></h2><p><code>git sparse-checkout (init | list | set | add | reapply | disable | check-rules | clean) [&lt;options&gt;]</code></p><p>可以直接修改 <code>.git/info/sparse-checkout</code> 文件来设置要检出的目录，修改后需要运行 <code>git sparse-checkout reapply</code> 来应用新的设置</p><p><code>.git/info/sparse-checkout</code> 文件格式与 <code>.gitignore</code> 一样（详见<a href="#gitignore-忽略文件的版本追踪">.gitignore</a> ），默认的内容为：</p><ul><li><code>/*</code> 表示检出所有文件</li><li><code>!/*/</code> 表示不检出任何目录</li></ul><h3 id="init-初始化稀疏检出" tabindex="-1">init 初始化稀疏检出 <a class="header-anchor" href="#init-初始化稀疏检出" aria-label="Permalink to “init 初始化稀疏检出”">​</a></h3><h4 id="option-git-sparse-checkout-init" tabindex="-1">option: <code>git sparse-checkout init</code> <a class="header-anchor" href="#option-git-sparse-checkout-init" aria-label="Permalink to “option: git sparse-checkout init”">​</a></h4><ul><li><code>--cone</code><ul><li><code>git sparse-checkout init --cone</code> 初始化稀疏检出，并启用锥形模式（cone mode）。锥形模式允许你指定要检出的目录，而不是单个文件</li></ul></li></ul><h3 id="set-设置要检出的目录列表" tabindex="-1">set 设置要检出的目录列表 <a class="header-anchor" href="#set-设置要检出的目录列表" aria-label="Permalink to “set 设置要检出的目录列表”">​</a></h3><ul><li><code>git sparse-checkout set &lt;dir1&gt; &lt;dir2&gt; ...</code> 设置要检出的目录列表，只有这些目录会被检出到工作区中</li></ul><h3 id="reapply-重新应用当前的稀疏检出设置" tabindex="-1">reapply 重新应用当前的稀疏检出设置 <a class="header-anchor" href="#reapply-重新应用当前的稀疏检出设置" aria-label="Permalink to “reapply 重新应用当前的稀疏检出设置”">​</a></h3><ul><li><code>git sparse-checkout reapply</code> 重新应用当前的稀疏检出设置，通常在修改了 <code>.git/info/sparse-checkout</code> 文件后使用，以确保新的设置生效</li></ul><h3 id="disable-禁用稀疏检出" tabindex="-1">disable 禁用稀疏检出 <a class="header-anchor" href="#disable-禁用稀疏检出" aria-label="Permalink to “disable 禁用稀疏检出”">​</a></h3><ul><li><code>git sparse-checkout disable</code> 禁用稀疏检出，恢复正常的检出行为，所有文件都会被检出到工作区中</li></ul><h1 id="gitignore-忽略文件的版本追踪" tabindex="-1">.gitignore 忽略文件的版本追踪 <a class="header-anchor" href="#gitignore-忽略文件的版本追踪" aria-label="Permalink to “.gitignore 忽略文件的版本追踪”">​</a></h1><blockquote><p><a href="https://www.bilibili.com/video/BV1EG4y1Z7WW/" target="_blank" rel="noreferrer">gitignore介绍视频</a></p></blockquote><p>不是所有文件都要保存到版本库中，像日志文件、临时文件和工具（像vscode）生成的文件。只能忽略没有被追踪的文件，先纳入版本管理后写入的无效。破解： <code>git rm -r --cached .</code> 清除本地缓存</p><ul><li>每项配置占一行</li><li>每行内容：名称/路径/模式匹配</li></ul><p>关于模式匹配：</p><ul><li>空行不匹配</li><li><code>#</code>: 注释</li><li><code>\\</code>: 转义</li><li><code>*</code> 匹配任何字符（0或多次），不可用来匹配 <code>/</code></li><li><code>?</code> 匹配1个字符，不可用来匹配 <code>/</code></li><li><code>/</code> 放开头：只能匹配根目录下的东西，比如 <code>/ax</code> 只能匹配根目录下的名称为 <code>ax</code> 的目录或文件；没有则会递归匹配</li><li><code>/</code> 放末尾：只匹配该名称的<strong>目录</strong></li><li><code>!</code> 重新被包含。但是若父目录被排除，用 <code>!</code> 也没用 <ul><li>案例：忽略public目录下所有文件，除了favicon.ico文件 <ul><li>错误： <ul><li>public</li><li>!public/favicon.ico</li></ul></li><li>正确： <ul><li>public/*</li><li>!public/favicon.ico</li></ul></li></ul></li></ul></li><li><code>[]</code> 匹配一个字符列表，比如 <code>a[mn]z</code> 可以匹配 <code>amz</code> 和 <code>anz</code></li><li><code>**</code> 匹配多级目录，比如 <code>a/**/b</code> 可以匹配 <code>a/b</code> <code>a/x/b</code> <code>a/x/y/b</code></li></ul><p>.gitignore 文件放置的东西，比如：</p><ul><li>目录名称</li><li>文件名称</li></ul><h2 id="帮助命令-check-ignore" tabindex="-1">帮助命令 <code>check-ignore</code> <a class="header-anchor" href="#帮助命令-check-ignore" aria-label="Permalink to “帮助命令 check-ignore”">​</a></h2><p><code>git check-ignore xxx.cpp</code> 检查该文件是否被忽略，若有输出则说明被忽略了</p><h3 id="option-12" tabindex="-1">option <a class="header-anchor" href="#option-12" aria-label="Permalink to “option”">​</a></h3><p><code>-v</code> 给出哪条规则忽略了这个文件</p>',130)]))}const u=o(d,[["render",l]]);export{p as __pageData,u as default};
